def generate_plant_uml(description):
    plant_symbols = {'A': ['C'],
                      'T': ['a']}

    for symbol in description[0].values():
        if '@startuml' not in symbol:
            raise ValueError('Invalid character in symbol')

        node_symbols = ast.literal_expr(symbol, '@startuml', 'a', 'B', 'C', 'D', 'E', 'S')

    for symbol in description[1]:
        if '@enduml' not in symbol:
            raise ValueError('Invalid character in symbol')

        node_symbols = ast.parse(node_symbols, '@enduml', 'a', 'B', 'C', 'D', 'E', 'S')

    return node_symbols
